UPDATE recharge_order
SET status = 'CLOSED',
    update_time = #{now,jdbcType=TIMESTAMP}
WHERE expire_time <= #{now,jdbcType=TIMESTAMP}
  AND status IN ('CREATED', 'PAYING')

UPDATE recharge_order
order_no = #{orderNo,jdbcType=VARCHAR}, user_id = #{userId,jdbcType=BIGINT}, channel = #{channel,jdbcType=VARCHAR}, amount_cent = #{amountCent,jdbcType=BIGINT}, status = #{status,jdbcType=VARCHAR}, subject = #{subject,jdbcType=VARCHAR}, pay_trade_no = #{payTradeNo,jdbcType=VARCHAR}, pay_url = #{payUrl,jdbcType=VARCHAR}, expire_time = #{expireTime,jdbcType=TIMESTAMP}, paid_time = #{paidTime,jdbcType=TIMESTAMP}, callback_time = #{callbackTime,jdbcType=TIMESTAMP}, callback_payload = #{callbackPayload,jdbcType=VARCHAR}, idempotency_key = #{idempotencyKey,jdbcType=VARCHAR}, biz_type = #{bizType,jdbcType=VARCHAR}, membership_pricing_config_id = #{membershipPricingConfigId,jdbcType=BIGINT}, membership_duration_months = #{membershipDurationMonths,jdbcType=SMALLINT}, update_time = #{updateTime,jdbcType=TIMESTAMP}
WHERE id = #{id,jdbcType=BIGINT}
